const owner = $env.GITHUB_REPO_OWNER || "kreativmonkey";
const repo = $env.GITHUB_REPO_NAME || "homelab-gitops";
const token = $env.GITHUB_TOKEN;
const autoMergeUsers = ["renovate[bot]"];
const api = ($env.GITHUB_API_URL || "https://api.github.com").replace(/\/$/, "");
const llmBase = ($env.LLM_BASE_URL || "https://api.openai.com/v1").replace(/\/$/, "");
const llmKey = $env.LLM_API_KEY || "";
const baseUrl = api + "/repos/" + owner + "/" + repo;
const headers = { Authorization: "Bearer " + token, Accept: "application/vnd.github+json" };
const PROCESSED_LABEL = "auto-merge-done";

async function gh(path, opts) {
  opts = opts || {};
  return this.helpers.httpRequest({
    method: opts.method || "GET",
    url: baseUrl + path,
    headers: headers,
    json: true,
    body: opts.body || undefined,
    timeout: 30000,
  });
}

async function addLabel(prNum) {
  try {
    await gh("/issues/" + prNum + "/labels", {
      method: "POST",
      body: { labels: [PROCESSED_LABEL] },
    });
  } catch (_) {}
}

async function getPrDiff(prNum) {
  const files = await gh("/pulls/" + prNum + "/files");
  return files.slice(0, 10).map(function(f) {
    return "File: " + f.filename + " (" + f.status + ", +" + f.additions + "/-" + f.deletions + ")\n"
      + (f.patch ? f.patch.slice(0, 2000) : "(binary or empty)");
  }).join("\n\n---\n\n");
}

async function callLlm(systemPrompt, userContent) {
  if (!llmKey) return null;
  try {
    const res = await this.helpers.httpRequest({
      method: "POST",
      url: llmBase + "/chat/completions",
      headers: {
        Authorization: "Bearer " + llmKey,
        "Content-Type": "application/json",
      },
      body: {
        model: "gpt-4o-mini",
        temperature: 0.2,
        max_tokens: 800,
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userContent },
        ],
      },
      json: true,
      timeout: 30000,
    });
    return res?.choices?.[0]?.message?.content || null;
  } catch (e) {
    return null;
  }
}

async function postAiComment(prNum, assessment) {
  try {
    await gh("/issues/" + prNum + "/comments", {
      method: "POST",
      body: { body: "## AI Review\n\n" + assessment + "\n\n---\n_Automated review by n8n_" },
    });
  } catch (_) {}
}

const prs = await gh("/pulls?state=open&per_page=50");
const results = [];

for (const pr of prs) {
  const author = pr.user.login;
  const labels = (pr.labels || []).map(function(l) { return l.name; });

  if (labels.indexOf(PROCESSED_LABEL) !== -1) continue;
  if (pr.mergeable === null) continue;

  // AI assessment for every new PR
  try {
    const diff = await getPrDiff(pr.number);
    const assessment = await callLlm(
      "You are a Kubernetes GitOps code reviewer. "
      + "Assess the PR diff for risk, correctness, and best practices. "
      + "Reply in German. Keep it under 400 characters. "
      + "Start with Risk: low/medium/high.",
      "PR #" + pr.number + " by @" + author + "\n"
      + "Title: " + (pr.title || "") + "\n\nDiff:\n" + diff
    );
    if (assessment) {
      await postAiComment(pr.number, assessment);
    }
  } catch (_) {}

  // Non-auto-merge: notify once
  if (autoMergeUsers.indexOf(author) === -1) {
    results.push({
      telegramText: "👤 *PR #" + pr.number + "* by @" + author + "\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
    await addLabel(pr.number);
    continue;
  }

  // Auto-merge candidate: check merge conflicts
  if (pr.mergeable === false) {
    results.push({
      telegramText: "🚫 *PR #" + pr.number + "* merge conflict (" + author + ")\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
    await addLabel(pr.number);
    continue;
  }

  // Check CI
  const checks = await gh("/commits/" + pr.head.sha + "/check-runs");
  const hasFailure = checks.check_runs.some(function(c) { return c.conclusion === "failure"; });
  const allSuccess = checks.check_runs.every(function(c) { return c.conclusion === "success"; });

  if (!allSuccess) {
    results.push({
      telegramText: "⏳ *PR #" + pr.number + "* CI "
        + (hasFailure ? "failed" : "pending") + " (" + author + ")\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
    if (hasFailure) await addLabel(pr.number);
    continue;
  }

  // Merge
  try {
    await gh("/pulls/" + pr.number + "/merge", {
      method: "PUT",
      body: { merge_method: "squash" },
    });
    results.push({
      telegramText: "✅ *PR #" + pr.number + " merged*\n"
        + (pr.title || "") + "\n"
        + "_by " + author + "_",
      parseMode: "Markdown",
    });
  } catch (e) {
    results.push({
      telegramText: "❌ *PR #" + pr.number + " merge failed*\n"
        + (pr.title || "") + "\n"
        + "_by " + author + "_\n"
        + String(e.message || e).slice(0, 200),
      parseMode: "Markdown",
    });
  }
  await addLabel(pr.number);
}

if (results.length === 0) {
  return [];
}

return results.map(function(r) { r.chatId = $env.TELEGRAM_CHAT_ID; return { json: r }; });
